!function(){
  function esc(v){return v==null?"":String(v).replace(/[&<>"']/g,function(c){return{"&":"&amp;","<":"&lt;",">":"&gt;","\"":"&quot;","'":"&#39;"}[c]})}
  function parseTime(v){var d=new Date(v);return isNaN(d.getTime())?null:d}
  function fmtDate(v){var d=parseTime(v);if(!d)return esc(v);var m=["Jan","Feb","Mar","Apr","Mei","Jun","Jul","Agu","Sep","Okt","Nov","Des"];return String(d.getDate()).padStart(2,"0")+" "+m[d.getMonth()]+" "+d.getFullYear()}
  function fmtClock(v){var d=parseTime(v);if(!d)return"";return String(d.getHours()).padStart(2,"0")+":"+String(d.getMinutes()).padStart(2,"0")}
  function statusOf(item){
    var now=Date.now(), user=window.State&&State.user&&State.user.id;
    var submitted=user&&localStorage.getItem("CBT_SUBMITTED_"+item.id+"_"+State.user.id)==="1";
    var finished=window.State&&State._schedulesForUserId===(State.user&&State.user.id)&&(item.status==="SELESAI"||item._lastRenderedStatus==="SELESAI");
    var out={rowClass:"locked",badge:"Belum Login",detail:"Belum Login",action:"Belum Login",disabled:true,actionType:"start",hasResult:false};
    if(!user)return out;
    if(now<Number(item.mulai)){out.rowClass="waiting";out.badge="Belum Mulai";out.detail="Belum Waktunya";out.action="Belum Mulai";return out}
    if(submitted||finished){out.rowClass="done";out.badge="Selesai";out.detail="Sudah Dikerjakan";out.action="Lihat Nilai";out.disabled=false;out.hasResult=true;return out}
    if(now>=Number(item.selesai)||item.status==="TUTUP"){out.rowClass="expired";out.badge="Selesai";out.detail="Ujian Selesai";out.action="Selesai";return out}
    var ver=window.getScheduleVersion?getScheduleVersion(item):String(item.versi_soal||0);
    if(localStorage.getItem("SOAL_"+item.id+"_v"+ver)!==null){
      var ts=localStorage.getItem("SOAL_"+item.id+"_v"+ver+"_date");
      out.rowClass="active";out.badge=ts&&Date.now()-parseInt(ts,10)>36e5?"Cache Ready":"Aktif";out.detail="Siap";out.action="Mulai";out.disabled=false;return out
    }
    out.rowClass="sync";out.badge="Belum Sinkron";out.detail="Unduh soal dulu";out.action="Sinkron";out.disabled=false;out.actionType="sync";return out
  }
  function getSchedules(){
    var list=Array.isArray(window.State&&State.schedules)?State.schedules.filter(Boolean):[];
    if(!list.length)try{var raw=localStorage.getItem("CBT_CACHE_JADWAL");if(raw){var data=JSON.parse(raw)||{};list=Object.keys(data).map(function(id){return Object.assign({id:id},data[id])})}}catch(e){}
    if(window.State&&State.user&&State.user.kelas){
      var kelas=String(State.user.kelas).toLowerCase();
      list=list.filter(function(item){
        var target=item.target_kelas||item.kelas_target||item.kelas||"";
        if(!target||String(target).toUpperCase()==="SEMUA"||String(target).toUpperCase()==="ALL")return true;
        return String(target).split(",").map(function(s){return s.trim().toLowerCase()}).filter(Boolean).some(function(s){return kelas.includes(s)||s.includes(kelas)})
      })
    }
    return list
  }
  function emptyState(){
    return '<div class="mobile-empty schedule-empty"><div class="mobile-empty-illustration schedule-empty-icon"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.7" stroke-linecap="round" stroke-linejoin="round"><path d="M7 3.75v3M17 3.75v3M4.75 8.5h14.5M6.5 5.75h11A2.5 2.5 0 0 1 20 8.25v9A2.75 2.75 0 0 1 17.25 20H6.75A2.75 2.75 0 0 1 4 17.25v-9a2.5 2.5 0 0 1 2.5-2.5Z"></path><path d="M9 13h6M9 16h3"></path></svg></div><h4>Belum bisa sinkron</h4><p>Data jadwal ujian masih kosong atau belum aktif.</p></div>'
  }
  function renderScheduleTable(){
    var listEl=document.getElementById("mobile-schedule-list"), countEl=document.getElementById("schedule-count");
    if(!listEl)return;
    var items=getSchedules();
    if(countEl)countEl.textContent=String(items.length);
    if(!items.length){listEl.innerHTML=emptyState();return}
    var html='<div class="schedule-table-wrap"><table class="schedule-table compact-schedule-table"><thead><tr><th>Tgl / Jam</th><th>Mapel</th></tr></thead><tbody>';
    items.forEach(function(item){
      var st=statusOf(item), action=st.hasResult?"view-result":st.actionType||"start";
      var mulai=fmtDate(item.mulai), selesai=fmtDate(item.selesai), jamMulai=fmtClock(item.mulai), jamSelesai=fmtClock(item.selesai);
      html+='<tr class="schedule-row '+esc(st.rowClass)+'">'+
        '<td class="schedule-datetime"><div class="schedule-date-line"><span>Mulai</span><strong>'+mulai+'</strong><small>'+esc(jamMulai)+'</small></div><div class="schedule-date-line"><span>Selesai</span><strong>'+selesai+'</strong><small>'+esc(jamSelesai)+'</small></div></td>'+
        '<td class="schedule-subject"><div class="schedule-subject-name">'+esc(item.nama||"Ujian")+'</div><button class="schedule-action-btn" data-exam-id="'+esc(item.id)+'" data-action="'+esc(action)+'" '+(st.disabled?"disabled":"")+'>'+esc(st.action)+'</button></td>'+
      '</tr>'
    });
    html+='</tbody></table></div>';
    listEl.innerHTML=html;
    listEl.querySelectorAll(".schedule-action-btn:not([disabled])").forEach(function(btn){
      btn.addEventListener("click",async function(){
        var action=btn.dataset.action, id=btn.dataset.examId;
        if(action==="view-result"){
          if(!State.user)return;
          window.showLoading&&showLoading("Mengambil nilai...");
          try{
            var res=await window.gasRun("getStudentResult",id,State.user.id);
            if(res.success){localStorage.setItem("CBT_LAST_RESULT",JSON.stringify(res.result));window.location.href="result.html"}
            else window.showCustomAlert&&showCustomAlert("Info",res.message||"Gagal mengambil nilai.","Info")
          }catch(err){window.showCustomAlert&&showCustomAlert("Error","Gagal memuat nilai: "+err.message,"Error")}
          finally{window.hideLoading&&hideLoading()}
          return
        }
        var item=(State.schedules||[]).find(function(x){return x.id===id});
        if(!item)return;
        action==="sync"?syncSingleExam(item):handleMobileScheduleTap(item)
      })
    })
  }
  function patch(){
    var base=window.renderMobileSchedule;
    if(typeof base!=="function"||base._scheduleTablePatched)return;
    var wrapped=function(){return renderScheduleTable()};
    wrapped._scheduleTablePatched=true;
    window.renderMobileSchedule=wrapped
  }
  function boot(){patch();renderScheduleTable()}
  document.addEventListener("DOMContentLoaded",function(){setTimeout(boot,0)});
  window.addEventListener("load",function(){boot();setTimeout(boot,300);setTimeout(boot,1200)});
  window.CBTScheduleTable={refresh:renderScheduleTable}
}();
